// NODE: Session Manager
// Receives Telegram updates from the n8n Telegram Trigger node and tracks
// 2-message session state per chat.
// Message 1: Voice audio only
// Message 2: Caption + One or more Video(s) → triggers pipeline
// (First video = A-Roll, Others = B-Roll)

const TELEGRAM_BOT_TOKEN = "8754596174:AAHVBRlpbtevRd0Lo55dK1rlleIyXJ6bXfc";

// The Telegram Trigger node exposes the update directly (not nested under .body)
const update = $input.first().json;
const message = update.message || update.edited_message || null;

if (!message) {
  return [{ json: { skip: true, reason: "no message" } }];
}

const chatId = String(message.chat.id);

// Load existing session from workflow static data
const staticData = $getWorkflowStaticData("global");
if (!staticData.sessions) staticData.sessions = {};

let session = staticData.sessions[chatId] || { step: 0 };

// Prevent duplicate processing if already in progress (but allow new voice notes)
if (session.step === 2 && !message.voice) {
  return [{ json: { skip: true, reason: "already processing" } }];
}

// ── STEP 1: Voice message ──────────────────────────────────────────────────
if (message.voice && (session.step === 0 || session.step === 2)) {
  const fileId = message.voice.file_id;

  // Resolve file path via Telegram API
  const fileInfoResp = await this.helpers.httpRequest({
    method: "GET",
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getFile?file_id=${fileId}`,
  });

  const filePath = fileInfoResp.result.file_path;
  const audioUrl = `https://api.telegram.org/file/bot${TELEGRAM_BOT_TOKEN}/${filePath}`;

  session = { step: 1, chatId, audioUrl, audioFileId: fileId, videos: [] };
  staticData.sessions[chatId] = session;

  // Acknowledge receipt
  await this.helpers.httpRequest({
    method: "POST",
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
    body: {
      chat_id: chatId,
      text: "🎙️ Got your voice note!\n\nNow send a single message (or an album) with:\n📝 Caption (as message text)\n🎬 One main video (A-roll)\n📸 One or more clips (B-roll)",
    },
    json: true,
  });

  return [{ json: { skip: true, reason: "waiting for step 2" } }];
}

// ── STEP 2: Accumulate Caption + Videos ──────────────────────────────────
if (session.step === 1) {
  const currentCaption = message.caption || message.text || "";
  const video = message.video;

  let updated = false;

  // 1. Accumulate Caption (if we don't have one yet)
  if (currentCaption && !session.caption) {
    session.caption = currentCaption;
    updated = true;
  }

  // 2. Accumulate Video
  if (video) {
    const videoInfoResp = await this.helpers.httpRequest({
      method: "GET",
      url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getFile?file_id=${video.file_id}`,
    });
    const videoUrl = `https://api.telegram.org/file/bot${TELEGRAM_BOT_TOKEN}/${videoInfoResp.result.file_path}`;

    if (!session.videos) session.videos = [];
    // Avoid duplicates by fileId
    if (!session.videos.find(v => v.fileId === video.file_id)) {
      session.videos.push({ fileId: video.file_id, url: videoUrl, duration: video.duration });
      updated = true;
    }
  }

  // Save updated session state
  staticData.sessions[chatId] = session;

  // 4. Check if we have everything needed to proceed
  // We need a caption and at least 2 videos (1 A-roll + at least 1 B-roll)
  const hasCaption = !!session.caption;
  const videoCount = (session.videos || []).length;
  const hasEnoughVideos = videoCount >= 2;

  if (hasCaption && hasEnoughVideos) {
    // TRIGGER PIPELINE
    session.step = 2; // Move to "processing" state
    staticData.sessions[chatId] = session;

    await this.helpers.httpRequest({
      method: "POST",
      url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
      body: {
        chat_id: chatId,
        text: `⚙️ All assets received (${videoCount} videos)! Starting generation pipeline...\n\nThis may take a few minutes ☕`,
      },
      json: true,
    });

    return [{
      json: {
        skip: false,
        chatId,
        audioUrl: session.audioUrl,
        videos: session.videos, // First is A-roll, others B-roll
        rawCaption: session.caption,
      },
    }];
  }

  // 5. Still collecting
  if (updated && !message.media_group_id) {
    const missing = [];
    if (!hasCaption) missing.push("📝 caption");
    if (videoCount === 0) missing.push("🎬 main video (A-roll)");
    if (videoCount === 1) missing.push("🎬 b-roll clips");

    await this.helpers.httpRequest({
      method: "POST",
      url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
      body: {
        chat_id: chatId,
        text: `📥 Received ${videoCount} video(s). Still missing: ${missing.join(", ")}.`,
      },
      json: true,
    });
  }

  return [{ json: { skip: true, reason: "collecting assets", hasCaption, videoCount } }];
}

// ── DEFAULT: Unexpected State Reset ───────────────────────────────────────
delete staticData.sessions[chatId];
await this.helpers.httpRequest({
  method: "POST",
  url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
  body: {
    chat_id: chatId,
    text: "👋 Send a voice note to start! The bot will guide you through the next steps.",
  },
  json: true,
});

return [{ json: { skip: true, reason: "unexpected state reset" } }];

// NODE: Transcribe Audio
// Sends the Telegram voice note URL to Replicate's Whisper for transcription
// Model: openai/whisper:8099696689d249cf8b122d833c36ac3f75505c666a395ca40ef26f68e7d3d16e

const REPLICATE_API_TOKEN = "r8_cYkGtnlW5dT9h0e6aThUBTtP1mhZ3Y33AgHUy";

const { audioUrl, chatId, videos, rawCaption } = $input.first().json;

// ── Step 1: Submit Transcription to Replicate ────────────────────────────
// We use "Prefer: wait" to try and get a synchronous response for short clips.
const submitResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://api.replicate.com/v1/models/openai/whisper/predictions",
  headers: {
    Authorization: `Bearer ${REPLICATE_API_TOKEN}`,
    "Content-Type": "application/json",
    "Prefer": "wait",
  },
  body: {
    input: {
      audio: audioUrl,
      language: "auto",
      translate: false,
      temperature: 0,
      transcription: "plain text",
      suppress_tokens: "-1",
      logprob_threshold: -1,
      no_speech_threshold: 0.6,
      condition_on_previous_text: true,
      compression_ratio_threshold: 2.4,
      temperature_increment_on_fallback: 0.2
    },
  },
});

let transcription = "";
let status = submitResp.status;
let pollUrl = submitResp.urls?.get;

// ── Step 2: Handle Immediate Success or Poll ─────────────────────────────
if (status === "succeeded") {
  transcription = submitResp.output?.transcription || submitResp.output || "";
} else {
  // If "wait" didn't finish, we poll
  if (!pollUrl) throw new Error("Replicate did not return a poll URL: " + JSON.stringify(submitResp));

  for (let i = 0; i < 30; i++) {
    await new Promise((r) => setTimeout(r, 5000));

    const statusResp = await this.helpers.httpRequest({
      method: "GET",
      url: pollUrl,
      headers: { Authorization: `Bearer ${REPLICATE_API_TOKEN}` },
    });

    if (statusResp.status === "succeeded") {
      transcription = statusResp.output?.transcription || statusResp.output || "";
      break;
    }

    if (statusResp.status === "failed") {
      throw new Error("Replicate transcription failed: " + (statusResp.error || JSON.stringify(statusResp)));
    }
  }
}

if (!transcription) {
  throw new Error("Failed to obtain transcription result");
}

return [{
  json: {
    chatId,
    audioUrl,
    videos,
    rawCaption,
    transcription,
  },
}];

// NODE: Generate A-Roll via Replicate (Pixverse Lip-sync)
// Uses the first video from the session as the talking head (A-roll).
// Lipsyncs it with the provided audio via Replicate.

const REPLICATE_API_TOKEN = "r8_cYkGtnlW5dT9h0e6aThUBTtP1mhZ3Y33AgHUy";

const { chatId, audioUrl, videos, rawCaption, transcription } = $input.first().json;

if (!videos || videos.length === 0) {
  throw new Error("No videos found in session. Need at least one for A-Roll.");
}

// First video in the list is the A-roll
const aRollSource = videos[0].url;

// ── STEP 1: Submit Prediction to Replicate ──────────────────────────────
const submitResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://api.replicate.com/v1/models/pixverse/lipsync/predictions",
  headers: {
    Authorization: `Bearer ${REPLICATE_API_TOKEN}`,
    "Content-Type": "application/json",
  },
  body: {
    input: {
      video: aRollSource,
      audio: audioUrl,
    },
  },
});

const predictionId = submitResp.id;
const pollUrl = submitResp.urls.get;

if (!predictionId || !pollUrl) {
  throw new Error("Replicate did not return prediction information: " + JSON.stringify(submitResp));
}

// ── STEP 2: Poll for completion ─────────────────────────────────────────
let aRollUrl = null;
for (let i = 0; i < 60; i++) { // Max 10 minutes (Replicate can be slow)
  await new Promise((r) => setTimeout(r, 10000)); // Poll every 10s

  const statusResp = await this.helpers.httpRequest({
    method: "GET",
    url: pollUrl,
    headers: { Authorization: `Bearer ${REPLICATE_API_TOKEN}` },
  });

  if (statusResp.status === "succeeded") {
    // Replicate output for pixverse/lipsync is usually the video URL string
    aRollUrl = statusResp.output;
    break;
  }

  if (statusResp.status === "failed") {
    throw new Error("Replicate prediction failed: " + (statusResp.error || JSON.stringify(statusResp)));
  }

  if (statusResp.status === "canceled") {
    throw new Error("Replicate prediction was canceled.");
  }
}

if (!aRollUrl) {
  throw new Error("Timeout waiting for Replicate lip-sync result");
}

return [{
  json: {
    chatId,
    aRollUrl,
    videos, // Keep all videos, first is A-Roll source, others are B-Roll
    rawCaption,
    transcription,
  },
}];

// NODE: Analyze B-Roll & Create Edit Plan
// Uses OpenRouter (GPT-4o vision) to analyze each b-roll video thumbnail,
// then uses the transcription to plan when to insert each b-roll clip.

const OPENROUTER_API_KEY = "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";
const TELEGRAM_BOT_TOKEN = "8754596174:AAHVBRlpbtevRd0Lo55dK1rlleIyXJ6bXfc";

const { chatId, aRollUrl, videos, rawCaption, transcription } = $input.first().json;

// ── Step 1: Describe each b-roll video (skip the first one as it's a-roll) ──
// We isolate just the b-roll clips (everything after the first video)
const brollClips = videos.slice(1);
const videoDescriptions = [];

for (const vid of brollClips) {
  const descResp = await this.helpers.httpRequest({
    method: "POST",
    url: "https://openrouter.ai/api/v1/chat/completions",
    headers: {
      Authorization: `Bearer ${OPENROUTER_API_KEY}`,
      "Content-Type": "application/json",
      "HTTP-Referer": "https://n8n.workflow",
      "X-Title": "Video Editor Bot",
    },
    body: {
      model: "openai/gpt-4o",
      messages: [
        {
          role: "user",
          content: [
            {
              type: "text",
              text: `You are analyzing a b-roll video clip for a social media video editor.
The video URL is: ${vid.url}
Duration: ${vid.duration || "unknown"} seconds

Based on the URL and context, describe:
1. What this b-roll clip likely shows (visual content, mood, setting)
2. What topics it matches
3. Ideal usage duration (2-5 seconds recommended)

Return JSON: {"description": "...", "keywords": ["..."], "suggestedDuration": 3}`,
            },
          ],
        },
      ],
      max_tokens: 300,
    },
  });

  let desc = { description: "b-roll clip", keywords: [], suggestedDuration: 3 };
  try {
    const raw = descResp.choices[0].message.content.replace(/```json|```/g, "").trim();
    desc = JSON.parse(raw);
  } catch (e) {
    desc.description = descResp.choices[0]?.message?.content || "b-roll clip";
  }

  videoDescriptions.push({ ...vid, ...desc });
}

// ── Step 2: Create edit plan using transcription ───────────────────────────
const brollSummary = videoDescriptions
  .map((v, i) => `Clip ${i}: "${v.description}" | keywords: ${v.keywords.join(", ")} | suggested: ${v.suggestedDuration}s`)
  .join("\n");

const planResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://openrouter.ai/api/v1/chat/completions",
  headers: {
    Authorization: `Bearer ${OPENROUTER_API_KEY}`,
    "Content-Type": "application/json",
    "HTTP-Referer": "https://n8n.workflow",
    "X-Title": "Video Editor Bot",
  },
  body: {
    model: "openai/gpt-4o",
    messages: [
      {
        role: "system",
        content: `You are a social media video editor. Plan b-roll inserts over an a-roll.
Rules:
- First 3 seconds: always show speaker (a-roll)
- B-roll should match speech
- Inserts: 2-5 seconds
- Return ONLY JSON`,
      },
      {
        role: "user",
        content: `TRANSCRIPTION:
"${transcription}"

AVAILABLE B-ROLL CLIPS:
${brollSummary}

Create a b-roll edit plan.
Return JSON array: [{"startTime": 5, "duration": 3, "clipIndex": 0, "reason": "..."}]`,
      },
    ],
    max_tokens: 800,
  },
});

let editPlan = [];
try {
  const raw = planResp.choices[0].message.content.replace(/```json|```/g, "").trim();
  editPlan = JSON.parse(raw);
} catch (e) {
  // fallback: insert clips evenly
  editPlan = videoDescriptions.map((v, i) => ({
    startTime: 4 + i * 6,
    duration: v.suggestedDuration || 3,
    clipIndex: i,
    reason: "evenly distributed fallback",
  }));
}

return [{
  json: {
    chatId,
    aRollUrl,
    brolls: videoDescriptions, // Renamed to brolls to be explicit
    rawCaption,
    transcription,
    editPlan,
  },
}];

// NODE: Compose Final Video (Local FFmpeg)
// Generates an FFmpeg command to composite b-roll over the talking head,
// executes it locally, and passes the output file path forward.
// Assumes FFmpeg is installed in the n8n environment.

const { execSync } = require('child_process');
const fs = require('fs');

const { chatId, aRollUrl, brolls, rawCaption, transcription, editPlan } = $input.first().json;

if (!aRollUrl) throw new Error("Missing A-Roll URL for composition");

// ── Step 1: Build Input List ──────────────────────────────────────────────
const inputs = [`-i "${aRollUrl}"`];
const planWithInputs = [];

for (const plan of editPlan) {
  const clip = brolls[plan.clipIndex];
  if (clip) {
    const inputIdx = inputs.length;
    inputs.push(`-i "${clip.url}"`);
    planWithInputs.push({ ...plan, inputIdx });
  }
}

// ── Step 2: Build Filter Complex ──────────────────────────────────────────
let filterParts = [];
let prevOutput = "[0:v]";
let brollLayerIdx = 1;

for (const plan of planWithInputs) {
  const scaledLabel = `scaled${plan.inputIdx}`;
  const outLabel = `layer${brollLayerIdx}`;

  filterParts.push(
    `[${plan.inputIdx}:v]scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920,setsar=1[${scaledLabel}]`
  );

  filterParts.push(
    `${prevOutput}[${scaledLabel}]overlay=0:0:enable='between(t,${plan.startTime},${plan.startTime + plan.duration})'[${outLabel}]`
  );

  prevOutput = `[${outLabel}]`;
  brollLayerIdx++;
}

const filterComplex = filterParts.join("; ");
const outputFilePath = `/tmp/final_${chatId || Date.now()}.mp4`;

// ── Step 3: Construct Full Command ────────────────────────────────────────
const ffmpegCommand = [
  "ffmpeg -y",
  inputs.join(" "),
  filterComplex ? `-filter_complex "${filterComplex}"` : "",
  `-map "${filterComplex ? prevOutput : '0:v'}"`,
  "-map 0:a",
  "-c:v libx264 -preset superfast -crf 23",
  "-c:a aac -b:a 128k",
  "-movflags +faststart",
  `-t 60`,
  `"${outputFilePath}"`
].filter(Boolean).join(" ");

// ── Step 4: Execute FFmpeg ────────────────────────────────────────────────
try {
  execSync(ffmpegCommand, { timeout: 120000, stdio: 'pipe' });
} catch (err) {
  throw new Error(`FFmpeg execution failed: ${err.stderr?.toString() || err.message}`);
}

if (!fs.existsSync(outputFilePath)) {
  throw new Error(`FFmpeg did not produce output file: ${outputFilePath}`);
}

return [{
  json: {
    chatId,
    outputFilePath,
    rawCaption,
    transcription,
    editPlan,
  },
}];

// NODE: Generate Caption & Send Final Video
// Enriches the raw caption with AI, adds viral hashtags,
// then uploads the local video file to Telegram.

const { execSync } = require('child_process');
const fs = require('fs');

const OPENROUTER_API_KEY = "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";
const TELEGRAM_BOT_TOKEN = "8754596174:AAHVBRlpbtevRd0Lo55dK1rlleIyXJ6bXfc";

const { chatId, outputFilePath, rawCaption, transcription, editPlan } = $input.first().json;

// ── Step 1: Generate enriched caption ─────────────────────────────────────
const captionResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://openrouter.ai/api/v1/chat/completions",
  headers: {
    Authorization: `Bearer ${OPENROUTER_API_KEY}`,
    "Content-Type": "application/json",
    "HTTP-Referer": "https://n8n.workflow",
    "X-Title": "Video Caption Generator",
  },
  body: {
    model: "openai/gpt-4o",
    messages: [
      {
        role: "system",
        content: "You are a viral social media content strategist specializing in short-form video (TikTok, Instagram Reels, YouTube Shorts).\nYour job: take a raw video caption idea + transcript and turn it into a hook-driven, engaging caption with viral hashtags.\n\nRules:\n- Start with a strong hook (first line = stop-the-scroll)\n- Keep it under 150 words\n- Natural, conversational tone\n- End with 5-8 highly relevant hashtags (mix of niche + broad)\n- Do not use emojis excessively (2-3 max)\n- Return ONLY the final caption text, no explanations",
      },
      {
        role: "user",
        content: `Raw caption idea: "${rawCaption}"\n\nVideo transcription (what I say in the video):\n"${transcription}"\n\nWrite the viral caption with hashtags:`,
      },
    ],
    max_tokens: 400,
  },
});

const viralCaption = captionResp.choices[0].message.content.trim();

// ── Step 2: Build edit plan summary ───────────────────────────────────────
const planSummary = editPlan
  .map(
    (p, i) =>
      `• B-roll ${p.clipIndex + 1} at ${p.startTime}s for ${p.duration}s — ${p.reason}`
  )
  .join("\n");

// ── Step 3: Upload video file to Telegram ─────────────────────────────────
// Write caption to a temp file to avoid shell-escaping issues with curl
const captionFile = `/tmp/caption_${chatId}.txt`;
fs.writeFileSync(captionFile, viralCaption);

try {
  const curlResult = execSync(
    `curl -s -X POST "https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendVideo" ` +
    `-F "chat_id=${chatId}" ` +
    `-F "video=@${outputFilePath}" ` +
    `-F "caption=<${captionFile}" ` +
    `-F "parse_mode=Markdown" ` +
    `-F "supports_streaming=true"`,
    { timeout: 60000 }
  ).toString();

  const parsed = JSON.parse(curlResult);
  if (!parsed.ok) {
    throw new Error(`Telegram API error: ${curlResult}`);
  }
} catch (err) {
  throw new Error(`Failed to send video to Telegram: ${err.message}`);
}

// ── Step 4: Send edit plan details as a follow-up message ─────────────────
await this.helpers.httpRequest({
  method: "POST",
  url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
  body: {
    chat_id: chatId,
    text: `✅ *Video ready!*\n\n*Edit Plan Used:*\n${planSummary}\n\n*Caption Generated:*\n${viralCaption}`,
    parse_mode: "Markdown",
  },
  json: true,
});

// ── Step 5: Clean up temp files ───────────────────────────────────────────
try { fs.unlinkSync(outputFilePath); } catch (e) { }
try { fs.unlinkSync(captionFile); } catch (e) { }

return [{
  json: {
    success: true,
    chatId,
    viralCaption,
    editPlan,
  },
}];

// NODE: Error Handler
// Catches any pipeline error and sends a friendly message to the user

const TELEGRAM_BOT_TOKEN = "8754596174:AAHVBRlpbtevRd0Lo55dK1rlleIyXJ6bXfc";

// Try to extract chatId from the last known good data
const inputData = $input.first().json;
const chatId = inputData.chatId || null;

const errorMessage = $input.first().error?.message || "Unknown error";

if (chatId) {
  await this.helpers.httpRequest({
    method: "POST",
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
    body: {
      chat_id: chatId,
      text: `❌ Something went wrong during video generation.\n\nError: ${errorMessage}\n\nPlease try again by sending your voice note first.`,
    },
    json: true,
  });
}

return [{ json: { handled: true, error: errorMessage } }];
